#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N;
        scanf("%lld", &N);
        if (N == 1) {
            printf("NO\n");
        } else {
            printf("YES\n");
        }
    }
    return 0;
}

